{"code":"import json

with open(locals()['var_function-call-5779811584283906500'], 'r') as f:
    articles = json.load(f)

keywords = ["maximum", "limit", "restriction", "prohibited", "only", "exceed", "allowed", "violation"]

relevant_articles = []

for article in articles:
    text = (article.get('title', '') + ' ' + article.get('summary', '') + ' ' + article.get('faq_answer__c', '')).lower()

    # Filter competitor
    if "competitor" in text:
        continue

    match_count = 0
    matches = []
    for kw in keywords:
        if kw in text:
            match_count += 1
            matches.append(kw)

    if match_count > 0:
        relevant_articles.append({
            "id": article['id'],
            "title": article['title'],
            "matches": matches,
            "summary": article['summary']
        })

print("__RESULT__:")
print(json.dumps(relevant_articles))"}

